var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제1 지구 사령 본부","JPN":"人類統合防衛軍第1地区指令本部","ENG":"United Humankind Defense Force, 1st District HQ","TWN":"人類共同保衛軍第一區司令總部","THA":"กองกำลังป้องกันมนุษยชาติ กองบัญชาการเขตที่ 1","VTN":"Lực Lượng Phòng Vệ Nhân Loại Thống Nhất, Trụ sở Quận 1","SCN":"人类综合防卫军第1区，司令总部","DEU":"1. Bezirk der Verteidigungsstreitkräfte der vereinigten Menschheit, Hauptquartier","FRA":"Quartier général du 1er district des Forces de défense unies de l'humanité"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"……그렇게 해서, 5종 침식체에 도달한 아포리아는 제2 방위선을 돌파하고 있습니다.","JPN":"……そのようにして、第5種侵食体になったアポリアは第2防衛線を突破しようとしています。","ENG":"...Thus, Aporia has reached Category 5 and is currently breaching the 2nd Defense Line.","TWN":"……因此，進化成5類侵蝕體的阿波利亞正在突破第2防線。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"시뮬레이터의 예측 결과에 따르면……","JPN":"シミュレーターの予測結果によると……","ENG":"According to the predictions of the simulation...","TWN":"根據模擬器的預測結果……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"앞으로 48시간 뒤에 이곳, 제1 방위선에 도달할 예정입니다, 사령관님.","JPN":"これから48時間後、ここ第1防衛線に到達します、司令官。","ENG":"In 48 hours, it will reach the 1st Defense Line, Commander.","TWN":"再過48小時，將會抵達第一防線，司令官。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"알겠네, 나가보게.","JPN":"わかった、下がりたまえ。","ENG":"Understood. You may go now.","TWN":"知道了，出去吧。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"후우, 결국 여기까지 왔나.","JPN":"ふう、結局ここまで来たか。","ENG":"*Sigh* So it has come to this.","TWN":"呼，還是到這裡來了嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"가용할 수 있는 모든 화력도, 방위군의 병력도 이젠 한계에 다다랐어.","JPN":"使用できる火力も、防衛軍の兵力ももう限界だ。","ENG":"We have exhausted all of our firepower, and the Defense Force is at capacity.","TWN":"現在可使用的所有火力，保衛軍的兵力都達到了極限。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"사전에 예측하지 못했던 네피림 사태와 달리 이번에는 시간도 있었고, 작전도 써볼 만큼 써봤어.","JPN":"事前に予測できなかったネフィリムのときとは異なり、今回は時間的余裕もあったし、あらゆる作戦を試してもみた。","ENG":"Unlike the Nephil incident, which we could not predict, this time we had time and used all the tactics we could.","TWN":"與之前無法預測的諾菲力事件不同，這次我們有足夠的時間，也嘗試了各種作戰計畫。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"쓸 수 있는 모든 방법을 다 써도, 인류는 끝내 그 괴물을 쓰러트릴 수 없는 건가.","JPN":"あらゆる手を尽くしても、人類は結局あの化け物を倒すことができないのか。","ENG":"After employing all of our resources against it, there seems to be no way for mankind to stop this monster.","TWN":"用盡一切辦法，人類還是不能戰勝那個怪物嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GUARD_EXILER_CAP_A","text":{"KOREA":"사령관님, 지금이라도 늦지 않았습니다!","JPN":"司令官、まだ間に合います！","ENG":"Commander, it's still not too late!","TWN":"司令官，現在還來得及！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GUARD_EXILER_CAP_A","text":{"KOREA":"그 안토노프라는 작자가 말했던 이주 플랜에 동참해야만 합니다!","JPN":"あのアントノフという者が言っていた移住計画に加わるべきです！","ENG":"We must join that Antonov's emigration plan!","TWN":"我們必須參與那個叫安東諾夫的傢伙所說的移居計畫！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_EXILER_CAP_A","text":{"KOREA":"그들이 요구하는 물자를 제공해준다면, 적어도 저희 자리는 마련할 수 있을 겁니다!","JPN":"やつらの要求する物資を提供すれば、私たちの席くらいは用意してもらえるでしょう！","ENG":"If we provide the supplies they are asking for, they will arrange us with a place on the ship!","TWN":"如果向他們提供所需的物資，至少能有我們的位置！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUARD_EXILER_CAP_B","text":{"KOREA":"맞습니다. 이제 우리 세계에 존재하는 함선은 그 엑자일러의 함선 한 대뿐입니다.","JPN":"そうです。もう我々の世界に存在する艦船は、あのエグザイラーの持つ一隻しかありません。","ENG":"He's right. The only remaining ship on this world is that Exile's.","TWN":"說的對，現在我們世界僅存的艦船，就只有那艘流浪者的艦船。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUARD_EXILER_CAP_B","text":{"KOREA":"적어도 그 엑자일러의 의견을 들어볼 가치는 있다고 생각합니다.","JPN":"少なくともあのエグザイラーの話を聞いてみる価値はあるかと思います。","ENG":"I believe it will be at least worthwhile to hear the Exile's viewpoint.","TWN":"我認為至少可以聽聽那個流浪者的意見。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"다들 아쉽게 됐군요.","JPN":"皆さん、残念でしたね。","ENG":"I'm afraid that will be difficult, everyone.","TWN":"很遺憾，各位。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"왜냐하면, 그 엑자일러는 이제 존재하지 않으니까요.","JPN":"そのエグザイラーはもういません。","ENG":"Because the Exile doesn't exist anymore.","TWN":"那個流浪者現在已經不存在了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};